function quantile(arr,q){
  var pos=(arr.length-1)*q;
  var lo=Math.floor(pos);
  var hi=Math.ceil(pos);
  if(lo===hi) return arr[lo];
  return arr[lo]*(hi-pos)+arr[hi]*(pos-lo);
}
var g=rawData.groups[0];
var vals=g.values.slice().sort(function(a,b){return a-b;});
var boxes=[];
var fracs=[[0.25,0.75,'M'],[0.125,0.875,'F'],[0.0625,0.9375,'E'],[0.03125,0.96875,'D']];
fracs.forEach(function(f,i){
  var lo=quantile(vals,f[0]);
  var hi=quantile(vals,f[1]);
  boxes.push({lo:lo,hi:hi,letter:f[2],level:i});
});
var median=quantile(vals,0.5);
transformedData={boxes:boxes,median:median,name:g.name,min:vals[0],max:vals[vals.length-1]};

