option={title:{text:'テール分布の解像度 (Boxen Plot)',left:'center'},tooltip:{formatter:function(p){if(p.seriesType==='scatter') return 'Median: '+p.value[1];return 'Range: '+p.value[1]+' - '+p.value[2];}},xAxis:{type:'category',data:[transformedData.name]},yAxis:{type:'value',name:'Value'},series:series};
